<?php require_once __DIR__.'/../config/db.php';require_once __DIR__.'/../includes/csrf.php';$error='';if($_SERVER['REQUEST_METHOD']==='POST'){if(verify_csrf($_POST['csrf_token']??'')){$st=$pdo->prepare('SELECT * FROM admins WHERE username=:u LIMIT 1');$st->execute(['u'=>trim($_POST['username']??'')]);$a=$st->fetch();if($a&&password_verify($_POST['password']??'',$a['password_hash'])){session_regenerate_id(true);$_SESSION['admin_id']=$a['id'];redirect('/admin/dashboard.php');}}$error='Identifiants invalides.';}?><!doctype html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Connexion admin</title><link rel="stylesheet" href="/assets/css/style.css"></head><body class="login-screen"><form class="login-card" method="post"><h1>Atlas Admin</h1><?php if($error):?><p class="error"><?=e($error)?></p><?php endif;?><?=csrf_field()?><label>Utilisateur<input name="username" required></label><label>Mot de passe<input type="password" name="password" required></label><button class="btn primary full">Connexion</button></form></body></html>